def process(list, fieldName):
    """Find struct with maximum value in a field"""
    if not list or not isinstance(list, (list, tuple)):
        return None, 0.0
    field = str(fieldName or '')
    max_val = None
    max_item = None
    for item in list:
        if isinstance(item, dict) and field in item:
            try:
                val = float(item[field])
                if max_val is None or val > max_val:
                    max_val = val
                    max_item = item
            except (TypeError, ValueError):
                pass
    return max_item, max_val if max_val is not None else 0.0
